const parse=r=>{if("string"==typeof r){if(/^0o?[0-7]+$/.test(r))return parseInt(r.replace(/^0o?/,""),8);if(/^[1-9][0-9]*$/.test(r))return parseInt(r,10);throw new Error(`invalid umask value: ${r}`)}if("number"!=typeof r)throw new Error(`invalid umask value: ${r}`);if((r=Math.floor(r))<0||r>511)throw new Error(`invalid umask value: ${r}`);return r},validate=(r,e,t)=>{try{return r[e]=parse(t),!0}catch(r){return!1}};module.exports={parse:parse,validate:validate};